 1→import { ToolMessage } from '@langchain/core/messages';
 2→import { createMiddleware } from 'langchain';
 3→import { formatError } from '../../common/utils';
 4→
 5→function formatToolFailureContent(error) {
 6→  return `Tool error: Please check your input and try again. (${error})`;
 7→}
 8→
 9→export function createToolErrorMiddleware(): ReturnType<typeof createMiddleware> {
10→  return createMiddleware({
11→    name: 'ToolErrorMiddleware',
12→    wrapToolCall: async (request, handler) => {
13→      try {
14→        return await handler(request);
15→      } catch (error) {
16→        const content = formatToolFailureContent(error);
17→
18→        // Return a ToolMessage so LangChain can continue the agent loop
19→        // instead of aborting the whole run on tool exceptions.
20→        return new ToolMessage({
21→          content,
22→          name: request.toolCall.name,
23→          tool_call_id: request.toolCall.id ?? '',
24→          status: 'error',
25→          artifact: { error: formatError(error) },
26→        });
27→      }
28→    },
29→  });
30→}
