  1→import { MemorySaver } from "@langchain/langgraph";
  2→import { MultiServerMCPClient } from "@langchain/mcp-adapters";
  3→import { createDeepAgent } from "deepagents";
  4→import { createMiddleware, DynamicStructuredTool } from "langchain";
  5→import { SystemMessage, ToolMessage } from "@langchain/core/messages";
  6→import { createToolErrorMiddleware } from "../middleware/tool-error.middleware";
  7→import { ConversationSandboxManager } from '../sandbox/conversation-sandbox.manager';
  8→import { BaseLanguageModel } from "@langchain/core/language_models/base";
  9→import { SANDBOX_SKILLS_ROOT } from '../sandbox/sandbox-skills.config';
 10→import { configSchema } from "../../config/config.schema";
 11→import type { SandboxBackendProtocol } from "deepagents";
 12→
 13→const memory = new MemorySaver();
 14→
 15→const VFS_RELATIVE_PATH_PROMPT = `## Important: Use Relative Paths in Execute Tool
 16→
 17→The sandbox environment does NOT support absolute paths in shell commands.
 18→When using the \`execute\` tool, you MUST use **relative paths** (without leading \`/\`) for all file operations.
 19→
 20→For example:
 21→- CORRECT: \`execute(command="python -c \\"import json; f=open('large_tool_results/get_dashboard_by_uid:5'); data=json.load(f); print(data)\\\"")\`
 22→- WRONG: \`execute(command="python -c \\"import json; f=open('/large_tool_results/get_dashboard_by_uid:5'); data=json.load(f); print(data)\\\"")\`
 23→
 24→This applies to ALL file paths used inside execute commands, including paths to files in \`large_tool_results/\` and any other local files.
 25→Note: The filesystem tools (read_file, write_file, ls, etc.) still use absolute paths starting with \`/\` — this restriction only applies to the \`execute\` tool.`;
 26→
 27→/**
 28→ * Middleware that instructs the LLM to use relative paths in execute tool commands,
 29→ * because the VFS sandbox environment does not support absolute paths in shell execution.
 30→ */
 31→const vfsRelativePathMiddleware = createMiddleware({
 32→  name: 'VfsRelativePathMiddleware',
 33→  wrapModelCall: async (request, handler) => {
 34→    const additionalPrompt = new SystemMessage({ content: VFS_RELATIVE_PATH_PROMPT });
 35→    return handler({
 36→      ...request,
 37→      messages: [additionalPrompt, ...request.messages],
 38→    });
 39→  },
 40→});
 41→
 42→/**
 43→ * Stricter threshold for evicting large tool results to filesystem.
 44→ * Default in deepagents SDK is 20000 tokens (80000 chars).
 45→ * We use 5000 tokens (20000 chars) to aggressively evict large MCP tool results
 46→ * (e.g., query_prometheus, get_dashboard_by_uid) that can return 60k-120k+ chars.
 47→ */
 48→const STRICT_TOOL_TOKEN_LIMIT = 5000;
 49→const NUM_CHARS_PER_TOKEN = 4;
 50→const STRICT_CHAR_LIMIT = STRICT_TOOL_TOKEN_LIMIT * NUM_CHARS_PER_TOKEN;
 51→
 52→/** Tools whose results should never be evicted (same as deepagents SDK). */
 53→const TOOLS_EXCLUDED_FROM_EVICTION = ['ls', 'glob', 'grep', 'read_file', 'edit_file', 'write_file'];
 54→
 55→function sanitizeToolCallId(toolCallId: string): string {
 56→  return toolCallId.replace(/\./g, '_').replace(/\//g, '_').replace(/\\/g, '_');
 57→}
 58→
 59→function createContentPreview(content: string, headLines = 5, tailLines = 5): string {
 60→  const lines = content.split('\n');
 61→  if (lines.length <= headLines + tailLines) {
 62→    return lines.map((line, i) => `${i + 1}\t${line.substring(0, 1000)}`).join('\n');
 63→  }
 64→  const head = lines.slice(0, headLines).map((line, i) => `${i + 1}\t${line.substring(0, 1000)}`).join('\n');
 65→  const truncation = `\n... [${lines.length - headLines - tailLines} lines truncated] ...\n`;
 66→  const tailStart = lines.length - tailLines + 1;
 67→  const tail = lines.slice(-tailLines).map((line, i) => `${tailStart + i}\t${line.substring(0, 1000)}`).join('\n');
 68→  return head + truncation + tail;
 69→}
 70→
 71→const TOO_LARGE_MSG = `Tool result too large, the result of this tool call {tool_call_id} was saved in the filesystem at this path: {file_path}
 72→You can read the result from the filesystem by using the read_file tool, but make sure to only read part of the result at a time.
 73→You can do this by specifying an offset and limit in the read_file tool call.
 74→For example, to read the first 100 lines, you can use the read_file tool with offset=0 and limit=100.
 75→
 76→Here is a preview showing the head and tail of the result (lines of the form
 77→... [N lines truncated] ...
 78→indicate omitted lines in the middle of the content):
 79→
 80→{content_sample}`;
 81→
 82→/**
 83→ * Creates a middleware that evicts large tool results to the VFS filesystem
 84→ * with a stricter threshold than the default deepagents SDK.
 85→ *
 86→ * Custom middleware runs innermost in the chain, so our eviction happens
 87→ * before the SDK's built-in filesystem middleware sees the result.
 88→ */
 89→function createStrictToolEvictionMiddleware(backend: SandboxBackendProtocol) {
 90→  return createMiddleware({
 91→    name: 'StrictToolEvictionMiddleware',
 92→    wrapToolCall: async (request, handler) => {
 93→      const toolName = request.toolCall?.name;
 94→      if (toolName && TOOLS_EXCLUDED_FROM_EVICTION.includes(toolName)) {
 95→        return handler(request);
 96→      }
 97→
 98→      const result = await handler(request);
 99→
100→      if (ToolMessage.isInstance(result) && typeof result.content === 'string' && result.content.length > STRICT_CHAR_LIMIT) {
101→        const toolCallId = request.toolCall?.id || result.tool_call_id;
102→        const evictPath = `/large_tool_results/${sanitizeToolCallId(toolCallId)}`;
103→
104→        let contentToWrite = result.content;
105→        try {
106→          const parsed = JSON.parse(contentToWrite);
107→          contentToWrite = JSON.stringify(parsed, null, 2);
108→        } catch {}
109→
110→        const writeResult = await backend.write(evictPath, contentToWrite);
111→        if (writeResult.error) return result;
112→
113→        const contentSample = createContentPreview(result.content);
114→        return new ToolMessage({
115→          content: TOO_LARGE_MSG
116→            .replace('{tool_call_id}', result.tool_call_id)
117→            .replace('{file_path}', evictPath)
118→            .replace('{content_sample}', contentSample),
119→          tool_call_id: result.tool_call_id,
120→          name: result.name,
121→          id: result.id,
122→          artifact: (result as any).artifact,
123→          status: result.status,
124→          metadata: result.metadata,
125→          additional_kwargs: result.additional_kwargs,
126→          response_metadata: result.response_metadata,
127→        });
128→      }
129→
130→      return result;
131→    },
132→  });
133→}
