 18→export const createPlannerNode = (llm: LanguageModelLike) => {
 19→  const deliveries = [
 20→    {
 21→      name: ENodeName.Writer,
 22→      description: '擅长基于所有收集到的信息生成清晰、结构化的 Markdown 文档报告',
 23→    },
 24→  ];
 25→
 26→  const agent = createAgent({
 27→    model: llm,
 28→    tools: [planning, next, askUserTool],
 29→    middleware: [
 30→      createToolErrorMiddleware(),
 31→      dynamicSystemPromptMiddleware(async () =>
 32→        render('deep-research/planner.md', {
 33→          currentTime: new Date().toLocaleString(),
 34→          members: [
 35→            {
 36→              name: ENodeName.Researcher,
 37→              description: '擅长使用提供的工具（包括但不限于联网搜索、链接读取、视觉理解等能力）收集信息',
 38→            },
 39→            ...deliveries,
 40→          ],
 41→          deliveries,
 42→        })
 43→      ),
 44→    ],
 45→  });
 46→
 47→  return async (state: State): Promise<Command> => {
 48→    const messages = state.messages.filter(
 49→      it =>
 50→        isToolCallOrResultMessage(it, [EToolName.Planning, EToolName.Next, EToolName.AskUser]) ||
 51→        (isTextOnlyAIMessage(it) && it.name === ENodeName.Planner) ||
 52→        isHumanMessage(it)
 53→    );
 54→
 55→    // ReactAgent 的 AgentNode 在 LLM 调用前会检查最后一条消息：
 56→    // 如果是 returnDirect 工具的 ToolMessage，则跳过 LLM 调用直接返回空消息。
 57→    // next 工具设有 returnDirect: true，在 researcher 交付后 next 的 ToolMessage
 58→    // 恰好是最后一条，导致 planner 二次调用时 LLM 被跳过，整个图直接结束。
 59→    // 追加一条消息来触发 LLM 分析任务完成状态并继续调度。
 60→    const lastMessage = messages.at(-1);
 61→    if (lastMessage && isToolMessage(lastMessage) && lastMessage.name === EToolName.Next) {
 62→      messages.push(new HumanMessage('请继续'));
 63→    }
 64→
 65→    log('planner input: ' + JSON.stringify(messages));
 66→    const response = await agent.invoke({ messages });
 67→    const additional = response.messages.slice(messages.length);
 68→    log('planner output: ' + JSON.stringify(additional));
 69→    const update: SetRequired<Partial<State>, 'messages'> = { messages: additional };
 70→
 71→    const planning = getToolCallResultMessage(additional, EToolName.Planning);
 72→    if (planning) {
 73→      log('update tasks: ' + JSON.stringify(planning.artifact));
 74→      update.tasks = planning.artifact.tasks;
 75→    }
 76→
 77→    const askUser = getToolCallResultMessage(additional, EToolName.AskUser);
 78→    if (askUser?.artifact) {
 79→      update.pendingInteraction = {
 80→        ...(askUser.artifact as IAskUserPayload),
 81→        agent: ENodeName.Planner,
 82→        resumeNode: ENodeName.Planner,
 83→      };
 84→      return new Command({ goto: ENodeName.Interaction, update });
 85→    }
 86→
 87→    const next = getToolCallResultMessage(additional, EToolName.Next);
 88→    if (next) {
 89→      if (!next.artifact) {
 90→        log(`Invalid input of tool 'next': ${JSON.stringify(getToolCall(additional, EToolName.Next))}`);
 91→        throw new Error('任务调度异常');
 92→      }
 93→
 94→      update.currentTaskIndex = next.artifact.index;
 95→
 96→      let tasks = update.tasks || state.tasks;
 97→      if (next.artifact.update) {
 98→        tasks = tasks.map((task, index) =>
 99→          index === next.artifact.index ? { ...task, ...next.artifact.update } : task
100→        );
101→        update.tasks = tasks;
102→      }
103→
104→      if (tasks[next.artifact.index].handler == ENodeName.Writer) {
105→        let modelName = '未知模型';
106→        if (llm instanceof ChatOpenAI) {
107→          modelName = llm.model;
108→        } else if (llm instanceof ChatAnthropic) {
109→          modelName = llm.model || '未知模型';
110→        }
111→        log(`规划最终文档输出: ${modelName}`);
112→      }
113→
114→      return new Command({ goto: tasks[next.artifact.index].handler || END, update });
115→    }
116→
117→    return new Command({ goto: END, update });
118→  };
119→};
