import { BaseLanguageModel } from '@langchain/core/language_models/base';
import { ChatDeepSeek } from '@langchain/deepseek';
import { ChatOpenAI } from '@langchain/openai';
import { configSchema } from './config.schema';


export enum EModelName {
  DeepSeekChat = 'deepseek-chat',
  Kimik2_5 = 'moonshotai/kimi-k2.5',
  MiniMaxM2_5 = 'minimax/minimax-m2.5',
  GLM5 = 'z-ai/glm-5',
  Qwen3_5 = 'qwen/qwen3.5-flash-02-23',
  Doubao_Sedd_1_6 = 'doubao/sedd-1.6',
}

// Model context limits are aligned with OpenRouter model pages:
// - deepseek/deepseek-chat: 128K context
// - minimax/minimax-m2.5: 196,608 context
// - z-ai/glm-5: 200K context
// - qwen/qwen3.5-flash-02-23: 256K context
export const MODEL_CONTEXT_WINDOWS: Record<EModelName, number> = {
  [EModelName.DeepSeekChat]: 128_000,
  [EModelName.Kimik2_5]: 262_144,
  [EModelName.MiniMaxM2_5]: 196_608,
  [EModelName.GLM5]: 200_000,
  [EModelName.Qwen3_5]: 1_000_000,
  [EModelName.Doubao_Sedd_1_6]: 256_000,
};

const modelFactories: Record<EModelName, () => BaseLanguageModel> = {
  [EModelName.DeepSeekChat]: () => new ChatDeepSeek({
    model: 'deepseek-chat',
    temperature: Number(configSchema.TEMPERATURE),
  }),
  [EModelName.Kimik2_5]: () => new ChatOpenAI({
    model: 'moonshotai/kimi-k2.5',
    apiKey: configSchema.OPENROUTER_API_KEY,
    configuration: { baseURL: configSchema.OPENROUTER_BASE_URL },
  }),
  [EModelName.MiniMaxM2_5]: () => new ChatOpenAI({
    model: 'minimax/minimax-m2.5',
    apiKey: configSchema.OPENROUTER_API_KEY,
    configuration: { baseURL: configSchema.OPENROUTER_BASE_URL },
  }),
  [EModelName.GLM5]: () => new ChatOpenAI({
    model: 'z-ai/glm-5',
    apiKey: configSchema.OPENROUTER_API_KEY,
    configuration: { baseURL: configSchema.OPENROUTER_BASE_URL },
  }),
  [EModelName.Qwen3_5]: () => new ChatOpenAI({
    model: 'qwen/qwen3.5-flash-02-23',
    apiKey: configSchema.OPENROUTER_API_KEY,
    configuration: {
      baseURL: configSchema.OPENROUTER_BASE_URL,
      defaultHeaders: {
        'enable_thinking': 'true',
      }
    },
  }),
  [EModelName.Doubao_Sedd_1_6]: () => new ChatOpenAI({
    model: 'ep-20260318173417-t9bvc',
    configuration: { baseURL: 'https://ark-cn-beijing.bytedance.net/api/v3', apiKey: "e4a0a203-38c2-4047-973d-de8003a825dd" },
  }),
};

const modelCache: Partial<Record<EModelName, BaseLanguageModel>> = {};

export function getModel(modelName: EModelName): BaseLanguageModel {
  const cachedModel = modelCache[modelName];
  if (cachedModel) {
    return cachedModel;
  }

  const nextModel = modelFactories[modelName]();
  modelCache[modelName] = nextModel;
  return nextModel;
}

